--

INSERT INTO `books` (`id`, `writerId`, `publisherId`, `categoryId`, `title`, `coverImage`, `ISBN`, `price`, `content`) VALUES
(2, 2, 2, 2, 'Bogyó és Babóca – A szivárvány', , '9786156911247', 3685, 'A történet Bogyó és Babóca barátságáról és közös kalandjairól szól, ezúttal a színes szivárvány felfedezésével a középpontban. A mese szeretettel és egyszerű tanulságokkal vezet be a kisgyerekek világába, miközben játékos, kedves szereplők mutatják meg a barátság, együttműködés és kíváncsiság fontosságát. Ideális olvasmány a legkisebbek számára.\r');
INSERT INTO `books` (`id`, `writerId`, `publisherId`, `categoryId`, `title`, `coverImage`, `ISBN`, `price`, `content`) VALUES
(3, 3, 3, 3, 'Gulliver utazásai', , '9630754428', 960, 'Gulliver négy különleges utazásának története egyszerre szórakoztató kalandregény és éles társadalmi szatíra. A lilliputi apró emberek, az óriások földje, a repülő sziget különc tudósai és a bölcs, lótestű houyhnhnmok mind olyan világok, melyek tükröt tartanak az emberiségnek. Swift műve a kalandokon keresztül az emberi természet hibáit, a politikai visszásságokat és a társadalmak furcsaságait leplezi le.\r');
INSERT INTO `books` (`id`, `writerId`, `publisherId`, `categoryId`, `title`, `coverImage`, `ISBN`, `price`, `content`) VALUES
(4, 4, 1, 4, 'Harry Potter és az Azkabani fogoly', , '9789636140878', 4227, 'Harry harmadik tanévében kiderül, hogy egy veszélyes bűnöző, Sirius Black megszökött az Azkabani börtönből, és látszólag őt keresi. A Roxfortba új fenyegetések érkeznek a dementorokkal együtt, miközben Harry múltjának titkai lassan felszínre kerülnek. A történet sötétebb hangulatú, izgalmas fordulókkal és váratlan igazságokkal teli fejezet a varázsvilágban.\r');
INSERT INTO `books` (`id`, `writerId`, `publisherId`, `categoryId`, `title`, `coverImage`, `ISBN`, `price`, `content`) VALUES
(5, 4, 1, 4, 'Harry Potter és a Tűz Serlege', , '9789636140571', 5990, 'Harry rejtélyes körülmények között bekerül a veszélyes Trimágus Tusába, ahol életveszélyes próbákon kell helytállnia. Ahogy a verseny halad előre, egyre nyilvánvalóbbá válik, hogy valaki a háttérből irányítja az eseményeket. A könyv mérföldkő a sorozatban: sötétebb tónusú, drámai befejezéssel és Voldemort visszatérésével, ami mindent megváltoztat a varázsvilágban.\r');
INSERT INTO `books` (`id`, `writerId`, `publisherId`, `categoryId`, `title`, `coverImage`, `ISBN`, `price`, `content`) VALUES
(6, 5, 4, 5, 'Stranger Things – Gyanakvó elmék', , '9789632666723', 5699, 'A regény a sorozat előzményeit meséli el Terry Ives szemszögéből, aki fiatal nőként bekerül a hawkinsi labor kísérletei közé. A titkos program veszélyes pszichikai teszteket végez rajta és társain, amelyek a későbbi események alapját képezik. A könyv bemutatja, hogyan kezdődött Eleven története és hogyan indultak a labor sötét, törvényszegő kísérletei, melyek később Hawkins egész városát veszélybe sodorták.');

