INSERT INTO `writers` (`id`, `name`, `bio`) VALUES
(1, 'Szoboszlai Zsolt', 'Magyar sportszakember és édesapa, aki fiáról, Szoboszlai Dominikról írt részletes és személyes hangvételű életrajzi könyvet. Műve betekintést ad egy világsztár futballista gyerekkorába, fejlődésébe és a családi háttérbe.\r'),
(2, 'Bartos Erika', 'Magyar írónő és illusztrátor, a népszerű Bogyó és Babóca mesesorozat alkotója. Művei kedves, egyszerű és szeretetteljes történeteikkel a legkisebb gyerekek kedvencei.\r'),
(3, 'Jonathan Swift', '18.századi ír író, esszéista és szatirikus, legismertebb műve a Gulliver utazásai. Írásai éles társadalomkritikát fogalmaznak meg humorral és iróniával.\r'),
(4, 'J.K.Rowling', 'Brit írónő, aki világhírűvé vált a Harry Potter sorozattal, amely minden idők egyik legsikeresebb könyvszériája. Munkái gazdag világépítésükről és erős karaktereikről ismertek.\r'),
(5, 'Gwenda Bond', 'Amerikai írónő, aki több ifjúsági és fantasy regényt írt, köztük a Stranger Things előzménykönyveit. Történetei gyakran misztikus, karakterközpontú világokat mutatnak be.'),
(6, 'Bartos Cs Istvan', 'Magyar írónő és illusztrátor, a népszerű Bogyó és Babóca mesesorozat alkotója. Művei kedves, egyszerű és szeretetteljes történeteikkel a legkisebb gyerekek kedvencei.\r');

